<?php/* * NOTICE OF LICENSE * *  This source file is subject to the Open Software License (OSL 3.0) *  that is bundled with this package in the file LICENSE.txt. *  It is also available through the world-wide-web at this URL: *  http://opensource.org/licenses/osl-3.0.php *  If you did not receive a copy of the license and are unable to *  obtain it through the world-wide-web, please send an email *  to license@q-sols.com so we can send you a copy immediately. * * *  @copyright   Copyright (c) 2010 Q-Solutions. (www.q-sols.com) *  @license     http://opensource.org/licenses/osl-3.0.php  Open Software License (OSL 3.0) *//** * Description of envelope * * @author Moiz Shabbir <moiz.sf@gmail.com> */class ControllerVajebaatReceipt extends CRUDController {    public function getLanguageAlias() {        return 'vajebaat/receipt';    }    public function init() {        $this->data = $this->load->language($this->getLanguageAlias());        $this->setModel(Make::a('vajebaat/receipt'));        $this->setAlias('vajebaat/receipt');        if (!isset($this->session->data['session_id'])) {            if (CURRENT_APPLICATION == APP_MOBILE) {                $this->session->data['redirect'] = makeUrl('vajebaat/receipt');            } else {                $this->session->data['redirect'] = makeUrl('vajebaat/receipt/insert');            }            $this->redirect(makeUrl('vajebaat/session'));        }        if (CURRENT_APPLICATION == APP_AAMIL) {            $this->data['is_module_aamil'] = 1;        } else {            $this->data['is_module_aamil'] = 0;        }        if (CURRENT_APPLICATION == APP_AAMIL_VIEW) {            $this->data['is_module_aamil_view'] = 1;        } else {            $this->data['is_module_aamil_view'] = 0;        }        if (CURRENT_APPLICATION == APP_BM) {            $this->data['is_module_bm'] = 1;        } else {            $this->data['is_module_bm'] = 0;        }        if (CURRENT_APPLICATION == APP_MOBILE) {            $this->data['is_module_mobile'] = 1;        } else {            $this->data['is_module_mobile'] = 0;        }        if (CURRENT_APPLICATION == APP_ONLINE) {            $this->data['is_module_online'] = 1;        } else {            $this->data['is_module_online'] = 0;        }    }    public function insert() {        if (($this->request->server['REQUEST_METHOD'] == 'POST') && $this->validateForm()) {            if (isset($this->request->post['multiple'])) {                $data = $this->request->post['multiple'];            } else {                $data[] = $this->request->post;            }//            d(date('Y-m-d H:i:s'));            $session = ARModel::factory('setup/session')->find_one($this->session->data['session_id']);            $envelope_no = $session->next_envelope_no;            $session->next_envelope_no = $session->next_envelope_no + 1;            $session->save();//            d(date('Y-m-d H:i:s'));            $barcode_no = $session->envelope_prefix . str_pad($envelope_no, 4, '0', STR_PAD_LEFT);//            d(date('Y-m-d H:i:s'));            $registers = $this->setRegister($data);//            d(date('Y-m-d H:i:s'));            $this->save($barcode_no, $session, $data, $registers);//            d(date('Y-m-d H:i:s'),true);//            $this->redirect(self::makeUrl($this->getAlias()) . '/insert&barcode_no=' . $barcode_no);            $this->redirect(self::makeUrl($this->getAlias()) . '/view_receipt&barcode_no=' . $barcode_no);        }        if (isset($this->request->get['barcode_no']) && $this->request->get['barcode_no']) {            $m_envelope = ARModel::factory('vajebaat/envelope')                    ->table_alias('e')                    ->join('momin', 'm.id = e.momin_id', 'm')                    ->select('e.id')                    ->select('e.barcode_no')                    ->select('m.sfno')                    ->where('e.barcode_no', $this->request->get['barcode_no'])                    ->find_one();            if ($m_envelope) {                $this->data['barcode_no'] = $m_envelope->barcode_no;            }        }        unset($this->session->data['multiple_entry']);        $this->getForm();    }    public function update() {        if (!isset($this->session->data['session_id'])) {            $this->session->data['redirect'] = makeUrl('vajebaat/seal/insert');            $this->redirect(makeUrl('vajebaat/session'));        }        if (!isset($this->request->get['id'])) {            $this->session->data['error_warning'] = 'Invalid Request';            $this->redirect(makeUrl('vajebaat/seal'));        }        $m_env = ORM::for_table('envelope')->find_one($this->request->get['id']);        if ($m_env) {            $envelopes = ORM::for_table('envelope')->where('barcode_no', $m_env->barcode_no)->where('session_id', $this->session->data['session_id'])->find_many(true);            if (count($envelopes) > 1) {                $this->session->data['error_warning'] = 'Cannot Edit Multiple Envelope';                $this->redirect(makeUrl('vajebaat/seal/recall') . '&barcode_no=' . $m_env->barcode_no);            }        } else {            $this->session->data['error_warning'] = 'Invalid Envelope';            $this->redirect(makeUrl('vajebaat/seal'));        }//        if (($this->request->server['REQUEST_METHOD'] == 'POST') && $this->validateForm()) {//            $session = ARModel::factory('setup/session')->find_one($this->session->data['session_id']);//            $envelope_no = $session->next_envelope_no;//            $session->next_envelope_no = $session->next_envelope_no + 1;//            $session->save();////            if (isset($this->session->data['multiple_entry'])) {//                foreach ($this->session->data['multiple_entry'] as $entry) {//                    $data = array();//                    $data = $entry;//                    $data['registers'] = $this->setRegister($data);//                    $barcode_no = $this->save($envelope_no, $session, $data);//                }//                unset($this->sessin->data['multiple_entry']);//            } else {//                $data = $this->request->post;//                $data['registers'] = $this->setRegister($data);//                $barcode_no = $this->save($envelope_no, $session, $data);//            }////            $this->redirect(self::makeUrl($this->getAlias()) . '/view_receipt&barcode_no=' . $barcode_no);//        }        $this->getForm();    }    public function cancel() {        if (($this->request->server['REQUEST_METHOD'] == 'GET')) {            $model = ARModel::factory('vajebaat/receipt')->find_one($this->request->get['id']);            $model->receipt_status_id = 2;            $model->amount = 0;            $model->bank_register_id = '';            $model->save();            if ($model->hasErrors()) {                $this->error = array_merge($this->error, $model->getErrors());            } else {                $this->data['model'] = $model;                $this->session->data['success'] = __('text_cancel_success');                $this->redirect(self::makeUrl($this->getAlias()) . $this->getUrl());            }        }        $this->getList();    }    protected function getList() {        parent::getList();        if (isset($this->request->get['filter']))            $aFilter = $this->request->get['filter'];        else if (isset($this->session->data['filter'][get_class($this)]))            $aFilter = $this->session->data['filter'][get_class($this)];        if(!isset($aFilter['eq']['r.session_id']))            $aFilter['eq']['r.session_id'] = $this->session->data['session_id'];        $this->request->get['filter'] = $aFilter;        $this->data['filter'] = isset($this->request->get['filter']) ? $this->request->get['filter'] : array();        $this->data['lists'] = array();        $aStatus[0] = '';        $aStatus[1] = $this->language->get('text_enabled');        $aStatus[2] = $this->language->get('text_disabled');        $this->data['user_group'] = $this->user->getUserGroupId();        $model = Make::a('vajebaat/receipt')                ->table_alias('r')                ->left_outer_join('session', 'r.session_id = s.id AND s.status = 1', 's')                ->left_outer_join('country', 's.country_id = c.id AND c.status = 1', 'c')                ->left_outer_join('city', 's.city_id = ct.id AND ct.status = 1', 'ct')                ->left_outer_join('user', 'u.id = r.created_by_id', 'u')                ->order_by_desc('r.created_at')                ->order_by_asc('r.sf_no')                ->select('r.*')                ->select_expr('CONCAT(r.receipt_prefix, LPAD(r.receipt_no,4,"0"))', 'receipt_no')                ->select('s.name', 'session')                ->select('c.name', 'country')                ->select('ct.name', 'city')                ->select('r.mohallah', 'mohallah')                ->select('r.momin', 'momin')                ->select('r.sf_no', 'sfno')                ->select('r.ejamaat_no', 'ejamaat_no')                ->select('u.display_name', 'created_by');        $user_group_id = $this->user->getUserGroupId();//        if ($user_group_id > 2) {//            $model = $model->where('r.created_by_id', $this->user->getId());//        }//        d(array($this->data['criteria'],$model),true);        $results = $this->applyFilter($model)                ->offset($this->data['criteria']['start'])                ->limit($this->data['criteria']['limit'])                ->order_by($this->data['criteria']['sort'], $this->data['criteria']['order'])                ->find_many();        //d($model->get_last_query());        foreach ($results as $oModel) {            $result = $oModel->toArray();            $action = array();            if ($result['receipt_status_id'] == 1) {//                $action[] = array(//                    'text' => $this->language->get('button_cancel'),//                    'href' => self::makeUrl($this->getAlias() . '/cancel') . '&id=' . $result['id'] . $url//                );            }            $this->data['envelopes'][] = array_merge($result, array(                'created_by_id' => $oModel->getCreator()->find_one()->display_name,                'modified_by_id' => $oModel->getUpdator()->find_one()->display_name,                'selected' => isset($this->request->post['selected']) && in_array($result['id'], $this->request->post['selected']),                'action' => $action                    ));        }        // d($this->data['envelopes'],true);        $this->data['arrSessions'] = CHtml::listData(ARModel::factory('setup/session')->find_many(), 'id', 'name', '', '');        $this->data['arrCountries'] = CHtml::listData(ARModel::factory('localisation/country')->where('status', '1')->find_many(), 'id', 'name', '', '');        if (isset($this->request->get['filter']['eq']['s.country_id']) && $this->request->get['filter']['eq']['s.country_id']) {            $filter_country = $this->request->get['filter']['eq']['s.country_id'];        } elseif (isset($this->session->data['filter'][get_class($this)]['eq']['s.country_id']) && $this->session->data['filter'][get_class($this)]['eq']['s.country_id']) {            $filter_country = $this->session->data['filter'][get_class($this)]['eq']['s.country_id'];        } else {            $filter_country = '';        }        if (isset($this->request->get['filter']['eq']['s.city_id']) && $this->request->get['filter']['eq']['s.city_id']) {            $filter_city = $this->request->get['filter']['eq']['s.city_id'];        } elseif (isset($this->session->data['filter'][get_class($this)]['eq']['s.city_id']) && $this->session->data['filter'][get_class($this)]['eq']['s.city_id']) {            $filter_city = $this->session->data['filter'][get_class($this)]['eq']['s.city_id'];        } else {            $filter_city = '';        }        if ($filter_country) {            $this->data['arrCities'] = CHtml::listData(ARModel::factory('localisation/city')->order_by_asc('name')->where('status', '1')->where('country_id', $filter_country)->find_many(), 'id', 'name', '', '');        } else {            $this->data['arrCities'] = CHtml::listData(ARModel::factory('localisation/city')->order_by_asc('name')->where('status', '1')->find_many(), 'id', 'name', '', '');        }        if ($filter_city) {            $this->data['arrMohallas'] = CHtml::listData(ARModel::factory('localisation/mohallah')->order_by_asc('name')->where('status', '1')->where('city_id', $filter_city)->find_many(), 'id', 'name', '', '');        } elseif ($filter_country) {            $this->data['arrMohallas'] = CHtml::listData(ARModel::factory('localisation/mohallah')->order_by_asc('name')->where('status', '1')->where('country_id', $filter_country)->find_many(), 'id', 'name', '', '');        } else {            $this->data['arrMohallas'] = CHtml::listData(ARModel::factory('localisation/mohallah')->order_by_asc('name')->where('status', '1')->find_many(), 'id', 'name', '', '');        }        $this->response->setOutput($this->render(), $this->config->get('config_compression'));    }    protected function getForm() {        parent::getForm();        $this->document->addScript('../mcimagemanager/js/mcimagemanager.js', Document::POS_HEAD);        if (isset($this->error['country'])) {            $this->data['error_country'] = $this->error['country'];        }        if (isset($this->error['zone'])) {            $this->data['error_zone'] = $this->error['zone'];        }        if (isset($this->error['city'])) {            $this->data['error_city'] = $this->error['city'];        }        $this->data['vajebaats'] = ARModel::factory('setup/vajebaat')->where('status', '1')->find_many(true);        $this->data['silafitras'] = ARModel::factory('setup/silafitra')                ->table_alias('a')                ->join('hyear_silafitra', 'b.silafitra_id = a.id', 'b')                ->join('hyear', 'b.hyear_id = h.id', 'h')                ->join('session', 's.hyear_id = h.id AND s.id = "' . $this->session->data['session_id'] . '"', 's')                ->where('a.status', '1')                ->select('a.*')                ->select('b.amount')                ->find_many(true);        $session = ARModel::factory('setup/session')->find_one($this->session->data['session_id']);        $this->data['banks'] = CHtml::listData(ARModel::factory('localisation/bank')->where('status', '1')->order_by_asc('name')->find_many(), 'id', 'name');        if ($this->getMethod() == 'update' && isset($this->request->get['id'])) {            $momin = ARModel::factory('localisation/momin')->find_one($this->model->momin_id);            if ($momin) {                $this->data['model']->momin = trim($momin->title . ' ' . $momin->name);                $this->data['model']->sfno = $momin->sfno;                $this->data['model']->ejamaat_no = $momin->ejamaat_no;                $mohallah = ARModel::factory('localisation/mohallah')->find_one($momin->mohallah_id);                if ($mohallah)                    $this->data['model']->mohallah = $mohallah->name;                $this->data['model']->amount_total = $this->model->amount_silafitra + $this->model->amount_vajebaat;            }            $arrChequeFor['B'] = 'Both';            $arrChequeFor['V'] = 'Vajebaat';            $arrChequeFor['S'] = 'Silafitra';            $sql = "SELECT sf.id, sf.name, hs.amount, es.quantity, es.quantity, es.total";            $sql .= " FROM `envelope` e";            $sql .= " INNER JOIN `session` s ON s.id = e.session_id";            $sql .= " INNER JOIN `hyear_silafitra` hs ON hs.hyear_id = s.hyear_id";            $sql .= " INNER JOIN `silafitra` sf ON sf.id = hs.silafitra_id";            $sql .= " LEFT JOIN `envelope_silafitra` es ON es.envelope_id = e.id AND es.silafitra_id = sf.id";            $sql .= ' WHERE e.id = "' . $this->model->id . '"';            $this->data['silafitras'] = ORM::for_table('silafitra')->raw_query($sql, array())->find_many(true);            $sql = "SELECT v.*, ev.amount";            $sql .= " FROM `vajebaat` v";            $sql .= ' LEFT JOIN `envelope_vajebaat` ev ON ev.vajebaat_id = v.id AND ev.envelope_id = "' . $this->model->id . '"';            $this->data['vajebaats'] = ORM::for_table('vajebaat')->raw_query($sql, array())->find_many(true);        }        $this->data['rdate'] = $session->date;        $this->data['ndate'] = next_bank_day($session->date);        $this->data['arrMohallas'] = CHtml::listData(ARModel::factory('localisation/mohallah')->order_by_asc('name')->where('status', '1')->find_many(), 'name', 'name', '', '');        $this->response->setOutput($this->render(), $this->config->get('config_compression'));    }    protected function validateForm() {        if ($this->validatePermission()) {            //TODO: Validation for insert or update record        }        if (!$this->error) {            return TRUE;        } else {            if (!isset($this->error['warning']))                $this->error['warning'] = 'Check for the field error';            return FALSE;        }    }    protected function validateDelete() {        if ($this->validatePermission()) {            //TODO: Validation for delete record        } else {            $this->error['warning'] = __('Error: You donot have permission to delete record');        }        if (!$this->error) {            return TRUE;        } else {            return FALSE;        }    }    public function view_receipt() {        if (isset($this->request->get['sf_no']) && $this->request->get['sf_no']) {            $m_seal = ARModel::factory('vajebaat/seal')                ->table_alias('s')                ->join('seal_detail', 'sd.seal_id = s.id', 'sd')                ->where('sd.sf_no', $this->request->get['sf_no'])                ->order_by_desc('s.created_at')                ->select('s.*')                ->find_one();            $this->redirect(makeUrl($this->getAlias().'/view_receipt&barcode_no='.$m_seal->barcode_no));        } elseif (isset($this->request->get['ejamaat_no']) && $this->request->get['ejamaat_no']) {            $m_seal = ARModel::factory('vajebaat/seal')                ->table_alias('s')                ->join('seal_detail', 'sd.seal_id = s.id', 'sd')                ->where('sd.ejamaat_no', $this->request->get['ejamaat_no'])                ->order_by_desc('s.created_at')                ->select('s.*')                ->find_one();            $this->redirect(makeUrl($this->getAlias().'/view_receipt&barcode_no='.$m_seal->barcode_no));        } elseif (isset($this->request->get['barcode_no']) && $this->request->get['barcode_no']) {            $m_seal = ARModel::factory('vajebaat/seal')                ->where('barcode_no', $this->request->get['barcode_no'])                ->order_by_desc('created_at')                ->find_one();        }        if ($m_seal) {            if (isset($this->session->data['receipts'])) {                unset($this->session->data['receipts']);            }            $m_receipt = ARModel::factory('vajebaat/receipt')->where('barcode_no', $m_seal->barcode_no)->find_one();            if ($m_receipt) {                $this->session->data['error_warning'] = 'Error: Receipt already created';                $this->redirect(makeUrl($this->getAlias()));            }            $sql = "SELECT sf_no ,ejamaat_no ,momin ,mohallah";            $sql .= " ,SUM(IF(payment_for='V',amount,0)) AS amount_vajebaat";            $sql .= " ,SUM(IF(payment_for='S',amount,0)) AS amount_silafitra";            $sql .= " FROM seal_detail";            $sql .= " WHERE seal_id = '" . $m_seal->id . "'";            $sql .= " GROUP BY sf_no, ejamaat_no, momin, mohallah";            $sfs = ORM::for_table('envelope')->raw_query($sql, array())->find_many(true);            $this->data['sfs'] = $sfs;            $sql = "SELECT sf_no, ejamaat_no, momin, mohallah, instrument_no, instrument_date, bank_id, bank_branch_id, instrument_amount";            $sql .= " ,SUM(IF(payment_for='V',amount,0)) AS v_amount";            $sql .= " ,SUM(IF(payment_for='S',amount,0)) AS s_amount";            $sql .= " FROM seal_detail";            $sql .= " WHERE seal_id = '" . $m_seal->id . "'";            $sql .= " GROUP BY sf_no, ejamaat_no, momin, mohallah, instrument_no, instrument_date, bank_id, bank_branch_id";            $m_envelopes = ORM::for_table('envelope')->raw_query($sql, array())->find_many();            if ($m_envelopes) {                $this->data['envelopes'] = array();                $total_v_amount = 0;                $total_s_amount = 0;                $amount_cash = 0;                foreach ($m_envelopes as $m_envelope) {                    $total_v_amount += $m_envelope->v_amount;                    $total_s_amount += $m_envelope->s_amount;                    if (is_null($m_envelope->instrument_no)) {                        $amount_cash += ($m_envelope->v_amount + $m_envelope->s_amount);                    }                    $this->data['envelopes'][] = array(                        'barcode_no' => $m_envelope->barcode_no,                        'sfno' => $m_envelope->sf_no,                        'ejamaat_no' => $m_envelope->ejamaat_no,                        'name' => $m_envelope->momin,                        'v_amount' => round($m_envelope->v_amount),                        's_amount' => round($m_envelope->s_amount),                        'instrument_no' => $m_envelope->instrument_no,                        'instrument_date' => $m_envelope->instrument_date,                        'instrument_amount' => round($m_envelope->instrument_amount)                    );                }            }            $this->data['barcode_no'] = $m_seal->barcode_no;            $this->data['amount_cash'] = number_format($amount_cash);            $this->data['amount_total'] = number_format($total_v_amount + $total_s_amount);            $this->data['edit'] = makeurl($this->getAlias() . '/update&id=' . $this->data['model']->id);            $this->data['cancel'] = makeurl($this->getAlias());            $this->template = $this->getAlias() . '_view.tpl';            $this->response->setOutput($this->render(), $this->config->get('config_compression'));        } else {            $this->session->data['error_warning'] = 'Invalid Request! Envelope is not sealed';            $this->redirect(makeurl($this->getAlias()));        }    }    public function print_receipt() {        //d($this->request->get, true);        if (isset($this->request->get['barcode_no']) && $this->request->get['barcode_no']) {            if (isset($this->session->data['receipts'])) {                unset($this->session->data['receipts']);            }            if (isset($this->session->data['combine_receipts'])) {                unset($this->session->data['combine_receipts']);            }            $receipts = ARModel::factory('vajebaat/receipt')                ->table_alias('r')                ->left_outer_join('bank_register', 'br.id = r.bank_register_id', 'br')                ->left_outer_join('bank', 'b.id = br.bank_id', 'b')                ->where('barcode_no', $this->request->get['barcode_no'])                ->select('b.name','bank_name')                ->select('br.instrument_no')                ->select('br.instrument_date')                ->select('r.*')                ->find_many(true);            //d(array($this->session->data['session_id'],$this->request->get['barcode_no'],$receipts),true);            if ($receipts) {                foreach ($receipts as $receipt) {                    $this->session->data['receipts'][] = $receipt['id'];                    $receipt_identity = $receipt['receipt_identity'];                    if(isset($this->session->data['combine_receipts'][$receipt_identity])) {                        $this->session->data['combine_receipts'][$receipt_identity]['amount'] += $receipt['amount'];                    } else {                        $this->session->data['combine_receipts'][$receipt_identity] = array(                            'hyear' => $receipt['hyear'],                            'barcode_no' => $receipt['barcode_no'],                            'ejamaat_no' => $receipt['ejamaat_no'],                            'sf_no' => $receipt['sf_no'],                            'momin' => $receipt['momin'],                            'mohallah' => $receipt['mohallah'],                            'receipt_prefix' => $receipt['receipt_prefix'],                            'receipt_no' => $receipt['receipt_no'],                            'receipt_identity' => $receipt_identity,                            'date' => $receipt['date'],                            'hdate' => $receipt['hdate'],                            'amount' => $receipt['amount'],                            'mode_of_payment' => $receipt['mode_of_payment'],                            'bank_name' => $receipt['bank_name'],                            'instrument_no' => $receipt['instrument_no'],                            'instrument_date' => $receipt['instrument_date'],                        );                    }                }            } else {                $seals = ARModel::factory('vajebaat/seal')                    ->table_alias('m')                    ->join('seal_detail', 'd.seal_id = m.id', 'd')                    ->left_outer_join('bank_register', 'br.id = d.bank_register_id', 'br')                    ->left_outer_join('bank', 'b.id = br.bank_id', 'b')                    ->where('barcode_no', $this->request->get['barcode_no'])                    ->where_gt('amount',0)                    ->select('m.envelope_id')                    ->select('m.barcode_no')                    ->select('b.name','bank_name')                    ->select('br.instrument_no')                    ->select('br.instrument_date')                    ->select('d.*')                    ->find_many(true);                foreach ($seals as $seal) {                    /*                     * Receipts will be created through vajebaat only                    if ($seal['payment_for'] == 'S') {                        $session = ARModel::factory('setup/session')->find_one($this->session-