ayment' => 'Cash',                    'amount_for' => 'V',                    'amount' => $adj_amount                );                $amount_vajebaat -= $adj_amount;                $amount_cash -= $adj_amount;            }            //            d(array($amount_silafitra, $amount_vajebaat, $amount_cash,$arrCheque,$arrRegister));            //Adjusting Silafitra / Vajebaat Amount through cheque mark as B            foreach ($arrCheque as $key => $cheque) {                $arrDate = explode("/", $cheque['cheque_date']);                $instrument_date = $arrDate[2].'-'.$arrDate[1].'-'.$arrDate[0];//                d(array('Silafitra',$arrCheque[$key],$amount_silafitra));                if ($arrCheque[$key]['cheque_amount'] > 0 && $amount_silafitra > 0) {                    $adj_amount = ($cheque['cheque_amount'] > $amount_silafitra ? $amount_silafitra : $cheque['cheque_amount']);                    $arrRegister[] = array(                        'sf_no' => $data['sfno'],                        'ejamaat_no' => $data['ejamaat_no'],                        'momin' => $data['momin'],                        'mohallah' => $data['mohallah'],                        'mode_of_payment' => 'Bank',                        'amount_for' => 'S',                        'amount' => $adj_amount,                        'cheque_no' => $cheque['cheque_no'],                        'cheque_date' => $instrument_date,                        'cheque_bank' => $cheque['cheque_bank'],                        'bank_branch' => $cheque['bank_branch'],                        'cheque_amount' => $cheque['cheque_amount'],                        'cheque_for' => $cheque['cheque_for'],                    );                    $amount_silafitra -= $adj_amount;                    $arrCheque[$key]['cheque_amount'] -= $adj_amount;                }//                d(array('Vajebaat',$arrCheque[$key],$amount_vajebaat));                if ($arrCheque[$key]['cheque_amount'] > 0 && $amount_vajebaat > 0) {          