lse {                $receipt_no = $session->next_receipt_no_vajebaat;                $receipt_prefix = $session->receipt_prefix_vajebaat;                $receipt_identity = $receipt_prefix . str_pad($receipt_no, 4, '0', STR_PAD_LEFT);                $session->next_receipt_no_vajebaat = $session->next_receipt_no_vajebaat + 1;            }            $session->save();            */            $sql = "SELECT *";            $sql .= " FROM receipt";            $sql .= " WHERE session_id = '" . $this->session->data['session_id'] . "'";            $sql .= " AND barcode_no = '" . $receipt['barcode_no'] . "'";            $sql .= " AND mode_of_payment = '" . $receipt['mode_of_payment'] . "'";            $sql .= " AND bank_register_id = '" . $receipt['bank_register_id'] . "'";            $mod_receipt = ORM::for_table('receipt')->raw_query($sql, array())->find_one();            if($mod_receipt) {                $receipt_no = $mod_receipt->receipt_no;                $receipt_prefix = $mod_receipt->receipt_prefix;                $receipt_identity = $mod_receipt->receipt_identity;            } else {                $session = ARModel::factory('setup/session')->find_one($this->session->data['session_id']);                $receipt_no = $session->next_receipt_no_vajebaat;                $receipt_prefix = $session->receipt_prefix_vajebaat;                $receipt_identity = $receipt_prefix . str_pad($receipt_no, 4, '0', STR_PAD_LEFT);                $session->next_receipt_no_vajebaat = $session->next_receipt_no_vajebaat + 1;                $session->save();            }            $m_receipt = ARModel::factory('vajebaat/receipt')->create();            $m_receipt->id = getGUID();            $m_receipt->envelope_id = $receipt['envelope_id'];            $m_receipt->seal_id = $receipt['seal_id'];            $m_receipt->session_id = $this->session->data['session_id'];            $m_receipt->hyear = $session->hyear_id;            $m_receipt->barcode_no = $receipt['barcode_no'];            $m_receipt->ejamaat_no = $receipt['ejamaat_no'];            $m_receipt->sf_no = $receipt['sf_no'];            $m_receipt->momin = $receipt['momin'];            $m_receipt->mohallah = $receipt['mohallah'];            $m_receipt->receipt_type = $receipt['payment_for'];            $m_receipt->receipt_prefix = $receipt_prefix;            $m_receipt->receipt_no = $receipt_no;            $m_receipt->receipt_identity = $receipt_identity;            $m_receipt->date = $session->date;            $m_receipt->hdate = $session->hdate;            $m_receipt->amount = $receipt['amount'];            $m_receipt->mode_of_payment = $receipt['mode_of_payment'];            $m_receipt->bank_register_id = $receipt['bank_register_id'];            $m_receipt->receipt_status_id = '1';            $m_receipt->created_at = date('Y-m-d H:i:s');            $m_receipt->created_by_id = $this->user->getId();//            $m_receipt->ip_address = $_SERVER['REMOTE_ADDR'];            $m_receipt->save();        }    }    public function print_pending() {        $receipts = ARModel::factory('vajebaat/receipt')            ->table_alias('r')            ->left_outer_join('bank_register', 'br.id = r.bank_register_id', 'br')            ->left_outer_join('bank', 'b.id = br.bank_id', 'b')            ->join('receipt_print', 'rp.receipt_identity = r.receipt_identity', 'rp')            ->where('r.session_id',$this->session->data['session_id'])            ->where('rp.is_print',0)            ->where('rp.created_by_id',$this->session->data['user_id'])            ->select('b.name','bank_name')            ->select('br.instrument_no')            ->select('br.instrument_date')            ->select('r.*')            ->order_by_asc('r.receipt_identity')            ->find_many(true);        $this->session->data['print_receipts'] = array();        foreach($receipts as $receipt) {            if(isset($this->session->data['print_receipts'][$receipt['receipt_identity']])) {                $this->session->data['print_receipts'][$receipt['receipt_identity']]['amount'] += $receipt['amount'];            } else {                $this->session->data['print_receipts'][$receipt['receipt_identity']] = array(                    'hyear' => $receipt['hyear'],                    'barcode_no' => $receipt['barcode_no'],                    'ejamaat_no' => $receipt['ejamaat_no'],                    'sf_no' => $receipt['sf_no'],                    'momin' => $receipt['momin'],                    'mohallah' => $receipt['mohallah'],                    'receipt_prefix' => $receipt['receipt_prefix'],                    'receipt_no' => $receipt['receipt_no'],                    'receipt_identity' => $receipt['receipt_identity'],                    'date' => $receipt['date'],                    'hdate' => $receipt['hdate'],                    'amount' => $receipt['amount'],                    'mode_of_payment' => $receipt['mode_of_payment'],                    'bank_name' => $receipt['bank_name'],                    'instrument_no' => $receipt['instrument_no'],                    'instrument_date' => $receipt['instrument_date'],                );            }            $sql = "UPDATE `receipt_print` SET is_print=1 WHERE `receipt_identity` = '".$receipt['receipt_identity']."'";            $this->db->query($sql);        }        $this->data['print_receipts'] = $this->session->data['print_receipts'];        $this->template = 'vajebaat/receipt_print.tpl';        $output = $this->render(true);        echo $output;        exit();    }}class PDF extends TCPDF {    public $data;    //Page header    public function Header() {    }    // Page footer    public function Footer() {        // Position at 15 mm from bottom        $this->SetY(-10);        // Set font        $this->SetFont('helvetica', 'I', 9);        // Page number        $this->Cell(0, 5, $this->data['notes'], 0, false, 'L', 0, '', 0, false, 'T', 'M');        $this->ln(5);        $this->SetFont('helvetica', '', 7);        $this->Cell(60, 5, $this->data['user_